import requests

KONG_ADMIN_URL = 'http://localhost:8001'

def create_service(service_name, service_url):
    response = requests.post(
        f"{KONG_ADMIN_URL}/services",
        json={
            "name": service_name,
            "url": service_url
        }
    )
    return response.json()

def create_route(service_name, paths):
    response = requests.post(
        f"{KONG_ADMIN_URL}/routes",
        json={
            "paths": paths,
            "service": {
                "name": service_name
            }
        }
    )
    return response.json()

def create_upstream(upstream_name):
    response = requests.post(
        f"{KONG_ADMIN_URL}/upstreams",
        json={
            "name": upstream_name
        }
    )
    return response.json()

def add_target_to_upstream(upstream_name, target_address, target_port):
    response = requests.post(
        f"{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets",
        json={
            "target": f"{target_address}:{target_port}"
        }
    )
    return response.json()

# Example usage
service_name = "my_service"
service_url = "http://my_service_url"
paths = ["/my_service"]
upstream_name = "my_upstream"
target_address = "192.168.1.1"
target_port = 80

# Create service
service = create_service(service_name, service_url)
print("Service created:", service)

# Create route
route = create_route(service_name, paths)
print("Route created:", route)

# Create upstream
upstream = create_upstream(upstream_name)
print("Upstream created:", upstream)

# Add target to upstream
target = add_target_to_upstream(upstream_name, target_address, target_port)
print("Target added to upstream:", target)